# Write CSV
header = ["id","title","genres","keywords","overview","cast","crew","vote_average","runtime","release_date","popularity","original_language"]

with open("indian_movies.csv", "w", newline="", encoding="utf-8") as f:
    writer = csv.writer(f)
    writer.writerow(header)
    for m in movies:
        mid, title, genres, keywords, overview, cast, crew_dir, vote_avg, runtime, rel_date, pop, lang = m
        # Convert genres to JSON format matching TMDB
        genres_json = json.dumps([{"id": i+1, "name": g.strip()} for i, g in enumerate(genres.split(","))])
        keywords_json = json.dumps([{"id": i+1, "name": k.strip()} for i, k in enumerate(keywords.split(","))])
        cast_json = json.dumps([{"name": c.strip(), "character": ""} for c in cast.split(",")])
        crew_json = json.dumps([{"name": crew_dir, "job": "Director"}])
        writer.writerow([mid, title, genres_json, keywords_json, overview, cast_json, crew_json, vote_avg, runtime, rel_date, pop, lang])

print(f"✅ Created indian_movies.csv with {len(movies)} movies")
